    public java.util.concurrent.CompletableFuture<Object> fetchMarketsV2(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object defaultType = this.safeString(this.options, "defaultType");
            var marginModequeryVariable = this.handleMarginModeAndParams("fetchMarketsV2", parameters);
            var marginMode = ((java.util.List<Object>) marginModequeryVariable).get(0);
            var query = ((java.util.List<Object>) marginModequeryVariable).get(1);
            Object promisesRaw = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            if (Helpers.isTrue(!Helpers.isEqual(marginMode, null)))
            {
                ((java.util.List<Object>)promisesRaw).add(this.publicSpotGetMarginSymbols(query));
            } else
            {
                ((java.util.List<Object>)promisesRaw).add(this.publicSpotGetTradesSymbols(query));
            }
            ((java.util.List<Object>)promisesRaw).add(this.publicSwapGetPublicInstruments(parameters));
            Object promises = (Helpers.promiseAll(promisesRaw)).join();
            Object spotMarkets = Helpers.GetValue(promises, 0);
            Object swapMarkets = Helpers.GetValue(promises, 1);
            //
            // spot and margin
            //
            //     {
            //         "symbol_list":[
            //             {
            //                 "order_types":["LIMIT","MARKET"],
            //                 "quote_asset":"USDT",
            //                 "minimum_value":2,
            //                 "amount_precision":4,
            //                 "status":"TRADING",
            //                 "minimum_amount":0.0001,
            //                 "symbol":"BTC_USDT",
            //                 "is_allow":1,
            //                 "zone":"MAIN",
            //                 "base_asset":"BTC",
            //                 "price_precision":2
            //             }
            //         ],
            //         "code":0
            //     }
            //
            // swap
            //
            //     {
            //         "code": 0,
            //         "data": [
            //             {
            //                 "instrument_id": "BTCUSDTPERP",
            //                 "type": "REAL",
            //                 "contract_type": "PERPETUAL",
            //                 "base_currency": "BTC",
            //                 "quote_currency": "USDT",
            //                 "clear_currency": "USDT",
            //                 "contract_value": "0.001",
            //                 "contract_value_currency": "BTC",
            //                 "is_inverse": false,
            //                 "is_trading": true,
            //                 "status": "ONLINE",
            //                 "price_precision": 4,
            //                 "tick_size": "0.0001",
            //                 "min_order_amount": 1,
            //                 "open_max_limits": [
            //                     {
            //                         "leverage": "50",
            //                         "max_limit": "1000000"
            //                     }
            //                 ]
            //             },
            //         ]
            //     }
            //
            Object spotData = this.safeValue(spotMarkets, "symbol_list", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object swapData = this.safeValue(swapMarkets, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object response = this.arrayConcat(spotData, swapData);
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
            {
                Object market = Helpers.GetValue(response, i);
                Object id = this.safeString2(market, "symbol", "instrument_id");
                Object baseId = this.safeString2(market, "base_asset", "base_currency");
                Object quoteId = this.safeString2(market, "quote_asset", "quote_currency");
                Object settleId = this.safeString(market, "clear_currency");
                Object base = this.safeCurrencyCode(baseId);
                Object quote = this.safeCurrencyCode(quoteId);
                Object settle = this.safeCurrencyCode(settleId);
                //
                // The status is documented in the exchange API docs as follows:
                // TRADING, HALT (delisted), BREAK (trading paused)
                // https://docs.digifinex.vip/en-ww/v3/#/public/spot/symbols
                // However, all spot markets actually have status === 'HALT'
                // despite that they appear to be active on the exchange website.
                // Apparently, we can't trust this status.
                // const status = this.safeString (market, 'status');
                // const active = (status === 'TRADING');
                //
                Object isAllowed = this.safeInteger(market, "is_allow", 1);
                Object type = ((Helpers.isTrue((Helpers.isEqual(defaultType, "margin"))))) ? "margin" : "spot";
                Object spot = Helpers.isEqual(settle, null);
                Object swap = !Helpers.isTrue(spot);
                Object margin = ((Helpers.isTrue((!Helpers.isEqual(marginMode, null))))) ? true : null;
                Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
                Object isInverse = null;
                Object isLinear = null;
                if (Helpers.isTrue(swap))
                {
                    type = "swap";
                    symbol = Helpers.add(Helpers.add(Helpers.add(Helpers.add(base, "/"), quote), ":"), settle);
                    isInverse = this.safeValue(market, "is_inverse");
                    isLinear = ((Helpers.isTrue((!Helpers.isTrue(isInverse))))) ? true : false;
                    Object isTrading = this.safeValue(market, "isTrading");
                    if (Helpers.isTrue(isTrading))
                    {
                        isAllowed = 1;
                    }
                }
                Object isActive = ((Helpers.isTrue(isAllowed))) ? true : false;
    final Object finalSymbol = symbol;
                final Object finalBase = base;
                final Object finalSettle = settle;
                final Object finalType = type;
                final Object finalIsLinear = isLinear;
                final Object finalIsInverse = isInverse;
                            ((java.util.List<Object>)result).add(new java.util.HashMap<String, Object>() {{
                    put( "id", id );
                    put( "symbol", finalSymbol );
                    put( "base", finalBase );
                    put( "quote", quote );
                    put( "settle", finalSettle );
                    put( "baseId", baseId );
                    put( "quoteId", quoteId );
                    put( "settleId", settleId );
                    put( "type", finalType );
                    put( "spot", spot );
                    put( "margin", margin );
                    put( "swap", swap );
                    put( "future", false );
                    put( "option", false );
                    put( "active", isActive );
                    put( "contract", swap );
                    put( "linear", finalIsLinear );
                    put( "inverse", finalIsInverse );
                    put( "contractSize", DigifinexCore.this.safeNumber(market, "contract_value") );
                    put( "expiry", null );
                    put( "expiryDatetime", null );
                    put( "strike", null );
                    put( "optionType", null );
                    put( "precision", new java.util.HashMap<String, Object>() {{
                        put( "amount", DigifinexCore.this.parseNumber(DigifinexCore.this.parsePrecision(DigifinexCore.this.safeString(market, "amount_precision"))) );
                        put( "price", DigifinexCore.this.parseNumber(DigifinexCore.this.parsePrecision(DigifinexCore.this.safeString(market, "price_precision"))) );
                    }} );
                    put( "limits", new java.util.HashMap<String, Object>() {{
                        put( "leverage", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                        put( "amount", new java.util.HashMap<String, Object>() {{
                            put( "min", DigifinexCore.this.safeNumber2(market, "minimum_amount", "min_order_amount") );
                            put( "max", null );
                        }} );
                        put( "price", new java.util.HashMap<String, Object>() {{
                            put( "min", DigifinexCore.this.safeNumber(market, "tick_size") );
                            put( "max", null );
                        }} );
                        put( "cost", new java.util.HashMap<String, Object>() {{
                            put( "min", DigifinexCore.this.safeNumber(market, "minimum_value") );
                            put( "max", null );
                        }} );
                    }} );
                    put( "created", null );
                    put( "info", market );
                }});
            }
            return result;
        });

    }

