    public Object parseBalance(Object response)
    {
        //
        // spot and margin
        //
        //     {
        //         "currency": "BTC",
        //         "free": 4723846.89208129,
        //         "total": 0
        //     }
        //
        // swap
        //
        //     {
        //         "equity": "0",
        //         "currency": "BTC",
        //         "margin": "0",
        //         "frozen_margin": "0",
        //         "frozen_money": "0",
        //         "margin_ratio": "0",
        //         "realized_pnl": "0",
        //         "avail_balance": "0",
        //         "unrealized_pnl": "0",
        //         "time_stamp": 1661487402396
        //     }
        //
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
        {
            Object balance = Helpers.GetValue(response, i);
            Object currencyId = this.safeString(balance, "currency");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Object free = this.safeString2(balance, "free", "avail_balance");
            Object total = this.safeString2(balance, "total", "equity");
            Helpers.addElementToObject(account, "free", free);
            Helpers.addElementToObject(account, "used", Precise.stringSub(total, free));
            Helpers.addElementToObject(account, "total", total);
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

    /**
     * @method
     * @name digifinex#fetchBalance
     * @description query for balance and get the amount of funds available for trading or funds locked in orders
     * @see https://docs.digifinex.com/en-ww/spot/v3/rest.html#spot-account-assets
     * @see https://docs.digifinex.com/en-ww/spot/v3/rest.html#margin-assets
     * @see https://docs.digifinex.com/en-ww/swap/v2/rest.html#accountbalance
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object marketType = null;
            var marketTypeparametersVariable = this.handleMarketTypeAndParams("fetchBalance", null, parameters);
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            var marginModequeryVariable = this.handleMarginModeAndParams("fetchBalance", parameters);
            var marginMode = ((java.util.List<Object>) marginModequeryVariable).get(0);
            var query = ((java.util.List<Object>) marginModequeryVariable).get(1);
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(marginMode, null)) || Helpers.isTrue(Helpers.isEqual(marketType, "margin"))))
            {
                marketType = "margin";
                response = (this.privateSpotGetMarginAssets(query)).join();
            } else if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
            {
                response = (this.privateSpotGetSpotAssets(query)).join();
            } else if (Helpers.isTrue(Helpers.isEqual(marketType, "swap")))
            {
                response = (this.privateSwapGetAccountBalance(query)).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(this.id, " fetchBalance() not support this market type")) ;
            }
            //
            // spot and margin
            //
            //     {
            //         "code": 0,
            //         "list": [
            //             {
            //                 "currency": "BTC",
            //                 "free": 4723846.89208129,
            //                 "total": 0
            //             },
            //             ...
            //         ]
            //     }
            //
            // swap
            //
            //     {
            //         "code": 0,
            //         "data": [
            //             {
            //                 "equity": "0",
            //                 "currency": "BTC",
            //                 "margin": "0",
            //                 "frozen_margin": "0",
            //                 "frozen_money": "0",
            //                 "margin_ratio": "0",
            //                 "realized_pnl": "0",
            //                 "avail_balance": "0",
            //                 "unrealized_pnl": "0",
            //                 "time_stamp": 1661487402396
            //             },
            //             ...
            //         ]
            //     }
            //
            Object balanceRequest = ((Helpers.isTrue((Helpers.isEqual(marketType, "swap"))))) ? "data" : "list";
            Object balances = this.safeValue(response, balanceRequest, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseBalance(balances);
        });

    }

