    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        // spot and margin
        //
        //     {
        //         "currency_mark": "BTC",
        //         "type": 100234,
        //         "num": -10,
        //         "balance": 0.1,
        //         "time": 1546272000
        //     }
        //
        // swap
        //
        //     {
        //         "currency": "USDT",
        //         "finance_type": 17,
        //         "change": "-3.01",
        //         "timestamp": 1650809432000
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object type = this.parseLedgerEntryType(this.safeString2(item, "type", "finance_type"));
        Object currencyId = this.safeString2(item, "currency_mark", "currency");
        Object code = this.safeCurrencyCode(currencyId, currency);
        currency = this.safeCurrency(currencyId, currency);
        Object amount = this.safeNumber2(item, "num", "change");
        Object after = this.safeNumber(item, "balance");
        Object timestamp = this.safeTimestamp(item, "time");
        if (Helpers.isTrue(Helpers.isEqual(timestamp, null)))
        {
            timestamp = this.safeInteger(item, "timestamp");
        }
        final Object finalTimestamp = timestamp;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", null );
            put( "direction", null );
            put( "account", null );
            put( "referenceId", null );
            put( "referenceAccount", null );
            put( "type", type );
            put( "currency", code );
            put( "amount", amount );
            put( "before", null );
            put( "after", after );
            put( "status", null );
            put( "timestamp", finalTimestamp );
            put( "datetime", DigifinexCore.this.iso8601(finalTimestamp) );
            put( "fee", null );
        }}, currency);
    }

