    public Object parseBorrowInterest(Object info, Object... optionalArgs)
    {
        //
        //     {
        //         "amount": 0.0006103,
        //         "side": "go_long",
        //         "entry_price": 31428.72,
        //         "liquidation_rate": 0.3,
        //         "liquidation_price": 10225.335481159,
        //         "unrealized_roe": -0.0076885829266987,
        //         "symbol": "BTC_USDT",
        //         "unrealized_pnl": -0.049158102631999,
        //         "leverage_ratio": 3
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(info, "symbol");
        Object amountString = this.safeString(info, "amount");
        Object leverageString = this.safeString(info, "leverage_ratio");
        Object amountInvested = Precise.stringDiv(amountString, leverageString);
        Object amountBorrowed = Precise.stringSub(amountString, amountInvested);
        Object currency = ((Helpers.isTrue((Helpers.isEqual(market, null))))) ? null : Helpers.GetValue(market, "base");
        Object symbol = this.safeSymbol(marketId, market);
        return new java.util.HashMap<String, Object>() {{
            put( "info", info );
            put( "symbol", symbol );
            put( "currency", currency );
            put( "interest", null );
            put( "interestRate", 0.001 );
            put( "amountBorrowed", DigifinexCore.this.parseNumber(amountBorrowed) );
            put( "marginMode", null );
            put( "timestamp", null );
            put( "datetime", null );
        }};
    }

