    public Object parseBorrowRate(Object info, Object... optionalArgs)
    {
        //
        //     {
        //         "valuation_rate": 1,
        //         "total": 1.92012186174,
        //         "free": 1.92012186174,
        //         "currency": "USDT"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.milliseconds();
        Object currencyId = this.safeString(info, "currency");
        return new java.util.HashMap<String, Object>() {{
            put( "currency", DigifinexCore.this.safeCurrencyCode(currencyId, currency) );
            put( "rate", 0.001 );
            put( "period", 86400000 );
            put( "timestamp", timestamp );
            put( "datetime", DigifinexCore.this.iso8601(timestamp) );
            put( "info", info );
        }};
    }

    public Object parseBorrowRates(Object info, Object codeKey)
    {
        //
        //     {
        //         "valuation_rate": 1,
        //         "total": 1.92012186174,
        //         "free": 1.92012186174,
        //         "currency": "USDT"
        //     },
        //
        Object result = new java.util.HashMap<String, Object>() {{}};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(info)); i++)
        {
            Object item = Helpers.GetValue(info, i);
            Object currency = this.safeString(item, codeKey);
            Object code = this.safeCurrencyCode(currency);
            Object borrowRate = this.parseBorrowRate(item);
            Helpers.addElementToObject(result, code, borrowRate);
        }
        return result;
    }

