    public Object parseFundingRate(Object contract, Object... optionalArgs)
    {
        //
        //     {
        //         "instrument_id": "BTCUSDTPERP",
        //         "funding_rate": "-0.00012",
        //         "funding_time": 1662710400000,
        //         "next_funding_rate": "0.0001049907085171607",
        //         "next_funding_time": 1662739200000
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(contract, "instrument_id");
        Object timestamp = this.safeInteger(contract, "funding_time");
        Object nextTimestamp = this.safeInteger(contract, "next_funding_time");
        Object fundingTimeString = this.safeString(contract, "funding_time");
        Object nextFundingTimeString = this.safeString(contract, "next_funding_time");
        Object millisecondsInterval = Precise.stringSub(nextFundingTimeString, fundingTimeString);
        return new java.util.HashMap<String, Object>() {{
            put( "info", contract );
            put( "symbol", DigifinexCore.this.safeSymbol(marketId, market) );
            put( "markPrice", null );
            put( "indexPrice", null );
            put( "interestRate", null );
            put( "estimatedSettlePrice", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "fundingRate", DigifinexCore.this.safeNumber(contract, "funding_rate") );
            put( "fundingTimestamp", timestamp );
            put( "fundingDatetime", DigifinexCore.this.iso8601(timestamp) );
            put( "nextFundingRate", DigifinexCore.this.safeNumber(contract, "next_funding_rate") );
            put( "nextFundingTimestamp", nextTimestamp );
            put( "nextFundingDatetime", DigifinexCore.this.iso8601(nextTimestamp) );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", null );
            put( "previousFundingDatetime", null );
            put( "interval", DigifinexCore.this.parseFundingInterval(millisecondsInterval) );
        }};
    }

    public Object parseFundingInterval(Object interval)
    {
        Object intervals = new java.util.HashMap<String, Object>() {{
            put( "3600000", "1h" );
            put( "14400000", "4h" );
            put( "28800000", "8h" );
            put( "57600000", "16h" );
            put( "86400000", "24h" );
        }};
        return this.safeString(intervals, interval, interval);
    }

    /**
     * @method
     * @name digifinex#fetchFundingRateHistory
     * @description fetches historical funding rate prices
     * @param {string} symbol unified symbol of the market to fetch the funding rate history for
     * @param {int} [since] timestamp in ms of the earliest funding rate to fetch
     * @param {int} [limit] the maximum amount of [funding rate structures]{@link https://docs.ccxt.com/?id=funding-rate-history-structure} to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [funding rate structures]{@link https://docs.ccxt.com/?id=funding-rate-history-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchFundingRateHistory(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchFundingRateHistory() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            if (!Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                throw new BadSymbol((String)Helpers.add(this.id, " fetchFundingRateHistory() supports swap contracts only")) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "instrument_id", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "start_timestamp", since);
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object response = (this.publicSwapGetPublicFundingRateHistory(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": 0,
            //         "data": {
            //             "instrument_id": "BTCUSDTPERP",
            //             "funding_rates": [
            //                 {
            //                     "rate": "-0.00375",
            //                     "time": 1607673600000
            //                 },
            //                 ...
            //             ]
            //         }
            //     }
            //
            Object data = this.safeValue(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object result = this.safeValue(data, "funding_rates", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object rates = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(result)); i++)
            {
                Object entry = Helpers.GetValue(result, i);
                Object marketId = this.safeString(data, "instrument_id");
                Object symbolInner = this.safeSymbol(marketId);
                Object timestamp = this.safeInteger(entry, "time");
                ((java.util.List<Object>)rates).add(new java.util.HashMap<String, Object>() {{
                    put( "info", entry );
                    put( "symbol", symbolInner );
                    put( "fundingRate", DigifinexCore.this.safeNumber(entry, "rate") );
                    put( "timestamp", timestamp );
                    put( "datetime", DigifinexCore.this.iso8601(timestamp) );
                }});
            }
            Object sorted = this.sortBy(rates, "timestamp");
            return this.filterBySymbolSinceLimit(sorted, symbol, since, limit);
        });

    }

