    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        // swap
        //
        //     {
        //         "instrument_id": "BTCUSDTPERP",
        //         "margin_mode": "crossed",
        //         "avail_position": "1",
        //         "avg_cost": "18369.3",
        //         "last": "18388.9",
        //         "leverage": "20",
        //         "liquidation_price": "383.38712921065553",
        //         "maint_margin_ratio": "0.005",
        //         "margin": "0.918465",
        //         "position": "1",
        //         "realized_pnl": "0",
        //         "unrealized_pnl": "0.021100000000004115",
        //         "unrealized_pnl_rate": "0.02297311274790451",
        //         "side": "long",
        //         "open_outstanding": "0",
        //         "risk_score": "0.4901960784313725",
        //         "margin_ratio": "0.40486964045976204",
        //         "timestamp": 1667960241758
        //     }
        //
        // margin
        //
        //     {
        //         "amount": 0.0010605,
        //         "side": "go_long",
        //         "entry_price": 18321.39,
        //         "liquidation_rate": 0.3,
        //         "liquidation_price": -52754.371758471,
        //         "unrealized_roe": -0.002784390267332,
        //         "symbol": "BTC_USDT",
        //         "unrealized_pnl": -0.010820048189999,
        //         "leverage_ratio": 5
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString2(position, "instrument_id", "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object marginMode = this.safeString(position, "margin_mode");
        if (Helpers.isTrue(!Helpers.isEqual(marginMode, null)))
        {
            marginMode = ((Helpers.isTrue((Helpers.isEqual(marginMode, "crossed"))))) ? "cross" : "isolated";
        } else
        {
            marginMode = "crossed";
        }
        Object timestamp = this.safeInteger(position, "timestamp");
        Object side = this.safeString(position, "side");
        if (Helpers.isTrue(Helpers.isEqual(side, "go_long")))
        {
            side = "long";
        } else if (Helpers.isTrue(Helpers.isEqual(side, "go_short")))
        {
            side = "short";
        }
        final Object finalMarginMode = marginMode;
        final Object finalMarket = market;
        final Object finalSide = side;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", symbol );
            put( "notional", DigifinexCore.this.safeNumber(position, "amount") );
            put( "marginMode", finalMarginMode );
            put( "liquidationPrice", DigifinexCore.this.safeNumber(position, "liquidation_price") );
            put( "entryPrice", DigifinexCore.this.safeNumber2(position, "avg_cost", "entry_price") );
            put( "unrealizedPnl", DigifinexCore.this.safeNumber(position, "unrealized_pnl") );
            put( "contracts", DigifinexCore.this.safeNumber(position, "avail_position") );
            put( "contractSize", DigifinexCore.this.safeNumber(finalMarket, "contractSize") );
            put( "markPrice", DigifinexCore.this.safeNumber(position, "last") );
            put( "side", finalSide );
            put( "hedged", null );
            put( "timestamp", timestamp );
            put( "datetime", DigifinexCore.this.iso8601(timestamp) );
            put( "maintenanceMargin", DigifinexCore.this.safeNumber(position, "margin") );
            put( "maintenanceMarginPercentage", DigifinexCore.this.safeNumber(position, "maint_margin_ratio") );
            put( "collateral", null );
            put( "initialMargin", null );
            put( "initialMarginPercentage", null );
            put( "leverage", DigifinexCore.this.safeNumber2(position, "leverage", "leverage_ratio") );
            put( "marginRatio", DigifinexCore.this.safeNumber(position, "margin_ratio") );
            put( "percentage", null );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
        }});
    }

    /**
     * @method
     * @name digifinex#setLeverage
     * @description set the level of leverage for a market
     * @see https://docs.digifinex.com/en-ww/swap/v2/rest.html#setleverage
     * @param {float} leverage the rate of leverage
     * @param {string} symbol unified market symbol
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.marginMode] either 'cross' or 'isolated', default is cross
     * @param {string} [params.side] either 'long' or 'short', required for isolated markets only
     * @returns {object} response from the exchange
     */
    public java.util.concurrent.CompletableFuture<Object> setLeverage(Object leverage2, Object... optionalArgs)
    {
        final Object leverage3 = leverage2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object leverage = leverage3;
            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " setLeverage() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            if (Helpers.isTrue(!Helpers.isEqual(Helpers.GetValue(market, "type"), "swap")))
            {
                throw new BadSymbol((String)Helpers.add(this.id, " setLeverage() supports swap contracts only")) ;
            }
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isLessThan(leverage, 1))) || Helpers.isTrue((Helpers.isGreaterThan(leverage, 100)))))
            {
                throw new BadRequest((String)Helpers.add(this.id, " leverage should be between 1 and 100")) ;
            }
            final Object finalLeverage = leverage;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "instrument_id", Helpers.GetValue(market, "id") );
                put( "leverage", finalLeverage );
            }};
            Object defaultMarginMode = this.safeString2(this.options, "marginMode", "defaultMarginMode");
            Object marginMode = this.safeStringLower2(parameters, "marginMode", "defaultMarginMode", defaultMarginMode);
            if (Helpers.isTrue(!Helpers.isEqual(marginMode, null)))
            {
                marginMode = ((Helpers.isTrue((Helpers.isEqual(marginMode, "cross"))))) ? "crossed" : "isolated";
                Helpers.addElementToObject(request, "margin_mode", marginMode);
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("marginMode", "defaultMarginMode")));
            }
            if (Helpers.isTrue(Helpers.isEqual(marginMode, "isolated")))
            {
                Object side = this.safeString(parameters, "side");
                if (Helpers.isTrue(!Helpers.isEqual(side, null)))
                {
                    Helpers.addElementToObject(request, "side", side);
                    parameters = this.omit(parameters, "side");
                } else
                {
                    this.checkRequiredArgument("setLeverage", side, "side", new java.util.ArrayList<Object>(java.util.Arrays.asList("long", "short")));
                }
            }
            return (this.privateSwapPostAccountLeverage(this.extend(request, parameters))).join();
        });

    }

